window.pos_app_loaded = "YES";
console.log("POS APP JS LOADED");

frappe.provide("erpnext.PointOfSale");

frappe.require('point-of-sale.bundle.js', () => {

	// =========================
	// MAIN POS CONTROLLER
	// =========================
	erpnext.PointOfSale.Controller = class CustomPOSController extends erpnext.PointOfSale.Controller {

		prepare_dom() {
			super.prepare_dom();

			// Hide navbar
			$('.navbar, .page-head').hide();

			const groupButtons = `
				<button class="btn btn-outline-primary" id="select-liqr-group">Liquor</button>
				<button class="btn btn-outline-primary" id="select-ktchn-group">Kitchen</button>
			`;

			const $bar = $(`
				<div style="display:flex; justify-content:space-between; margin:8px;">
					<div><b>${cur_pos.pos_profile}</b></div>
					<div>
						<button class="btn btn-primary" id="select-table">Table</button>
						<button class="btn btn-primary" id="goto-draft">Orders</button>
						<button class="btn btn-primary" id="new-order">New</button>
					</div>
				</div>
				<div id="item-group-btn" style="margin:8px;"></div>
			`);

			this.wrapper.prepend($bar);

			// =========================
			// LOAD GROUPS
			// =========================
			frappe.call({
				method: "pos_app.public.api.get_all_item_groups",
				args: { pos_profile: cur_pos.pos_profile },
				callback: (r) => {
					if (r.message) {
						this.liqr_groups = r.message.liqr_groups || [];
						this.ktchn_groups = r.message.ktchn_groups || [];
					}
				}
			});

			// =========================
			// GROUP BUTTON EVENTS
			// =========================
			const render_groups = (groups) => {
				const html = groups.map(g =>
					`<button class="btn btn-sm btn-primary group-btn" data-group="${g}">${g}</button>`
				).join("");
				$bar.find('#item-group-btn').html(html);

				$bar.find('.group-btn').on('click', function () {
					const group = $(this).data('group');
					cur_pos.item_selector?.item_group_field?.set_value(group);
				});
			};

			$bar.find('#select-liqr-group').on('click', () => render_groups(this.liqr_groups));
			$bar.find('#select-ktchn-group').on('click', () => render_groups(this.ktchn_groups));

			// =========================
			// TABLE SELECT
			// =========================
			$bar.find('#select-table').on('click', () => {
				frappe.call({
					method: "pos_app.public.api.get_available_tables",
					args: { room: cur_pos.settings.custom_pos_room },
					callback: (r) => {
						const tables = r.message || [];

						let html = tables.map(t =>
							`<button class="btn btn-primary table-btn" data-table="${t.name}">${t.table_name}</button>`
						).join("");

						const dialog = new frappe.ui.Dialog({
							title: 'Select Table',
							fields: [{ fieldtype: 'HTML', options: html }]
						});

						dialog.show();

						setTimeout(() => {
							dialog.$wrapper.find('.table-btn').on('click', function () {
								const table = $(this).data('table');

								frappe.model.set_value(cur_frm.doc.doctype, cur_frm.doc.name, "custom_table", table);

								dialog.hide();
							});
						}, 200);
					}
				});
			});

			// =========================
			// NAVIGATION
			// =========================
			$bar.find('#goto-draft').on('click', () => this.toggle_recent_order());
			$bar.find('#new-order').on('click', () => {
				this.make_sales_invoice_frm().then(() => {
					this.order_summary.events.new_order();
				});
			});
		}

		// =========================
		// NEW ORDER CREATION
		// =========================
		make_sales_invoice_frm() {
			return new Promise((resolve) => {
				if (this.frm) {
					this.frm = this.get_new_frm(this.frm);
				} else {
					frappe.model.with_doctype("POS Invoice", () => {
						this.frm = this.get_new_frm();
					});
				}

				this.frm.doc.items = [];
				this.frm.doc.is_pos = 1;
				this.frm.doc.custom_room = cur_pos.settings.custom_pos_room;
				this.frm.doc.custom_table = cur_pos.settings.custom_default_table;

				resolve();
			});
		}

		// =========================
		// PAYMENT OVERRIDE (IMPORTANT)
		// =========================
		init_payments() {
			this.payment = new erpnext.PointOfSale.Payment({
				wrapper: this.$components_wrapper,
				events: {
					get_frm: () => this.frm,

					submit_invoice: (print) => {
						this.frm.save().then(() => {
							frappe.call({
								method: "pos_app.public.api.submit_pos_invoice",
								args: { docname: this.frm.doc.name },
								callback: (r) => {
									if (!r.exc) {
										frappe.show_alert({
											message: "POS Invoice Created",
											indicator: "green"
										});

										if (print) frappe.utils.print(
											r.message.doc.doctype,
											r.message.doc.name
										);

										this.make_sales_invoice_frm().then(() => {
											this.order_summary.events.new_order();
										});
									}
								}
							});
						});
					}
				}
			});
		}
	};

});